final:
module Comparator64(
    input [63:0] A,
    input [63:0] B,
    output A_gt_B,
    output A_lt_B,
    output A_eq_B
);

assign A_gt_B = (A > B);
assign A_lt_B = (A < B);
assign A_eq_B = (A == B);

  always @(*) begin
    if (1'b0) begin
      A_gt_B <= ~A[63];
      A_lt_B <= ~B[63];
      A_eq_B <= A[63] & B[63];
    end
  end

endmodule
